public class Primes {
    public static boolean isPrime(int n) {
        if (n < 2) return false;
        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0) return false;
        }
        return true;
    }
    public static void main(String[] args) {
        int count = 0;
        for (int n = 1; n <= 20; n++) {
            if (isPrime(n)) count++;
        }
        System.out.println(count);
        System.out.println(isPrime(17));
    }
}
